{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "转盘首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-wheel-view",
          "role": "state",
          "binding": "/wheel/currentIndex"
        },
        {
          "id": "home-spin-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "home-result-card",
          "role": "assertion",
          "binding": "/wheel/resultDish"
        },
        {
          "id": "home-share-result-button",
          "role": "action",
          "event": "open-share-result"
        },
        {
          "id": "home-spin-again-button",
          "role": "action",
          "event": "spin-wheel"
        }
      ]
    },
    {
      "id": "ingredients-page",
      "surfaceId": "ingredients",
      "pageId": "ingredients-page",
      "name": "冰箱食材",
      "route": "pages/Ingredients",
      "tabId": "tab-ingredients",
      "semanticTargets": [
        {
          "id": "ingredients-input",
          "role": "input",
          "binding": "/ingredients/newItemText"
        },
        {
          "id": "ingredients-add-button",
          "role": "action",
          "event": "add-ingredient"
        },
        {
          "id": "ingredients-list",
          "role": "list",
          "binding": "/ingredients/list",
          "itemIdPattern": "ingredient-item-{id}",
          "emptyStateId": "ingredients-empty-state"
        },
        {
          "id": "ingredients-recommend-button",
          "role": "action",
          "event": "recommend-by-ingredients"
        },
        {
          "id": "ingredients-results-list",
          "role": "list",
          "binding": "/ingredients/recommendResults",
          "itemIdPattern": "ingredients-dish-{id}",
          "emptyStateId": "ingredients-results-empty-state"
        }
      ]
    },
    {
      "id": "mood-page",
      "surfaceId": "mood",
      "pageId": "mood-page",
      "name": "心情筛选",
      "route": "pages/Mood",
      "tabId": "tab-mood",
      "semanticTargets": [
        {
          "id": "mood-mood-selector",
          "role": "input",
          "binding": "/mood/selectedMood"
        },
        {
          "id": "mood-meal-time-selector",
          "role": "input",
          "binding": "/mood/selectedMealTime"
        },
        {
          "id": "mood-taste-selector",
          "role": "input",
          "binding": "/mood/selectedTaste"
        },
        {
          "id": "mood-filter-button",
          "role": "action",
          "event": "filter-dishes"
        },
        {
          "id": "mood-results-list",
          "role": "list",
          "binding": "/mood/filterResults",
          "itemIdPattern": "mood-dish-{id}",
          "emptyStateId": "mood-results-empty-state"
        },
        {
          "id": "mood-use-button",
          "role": "action",
          "event": "use-dish"
        }
      ]
    },
    {
      "id": "checkin-page",
      "surfaceId": "checkin",
      "pageId": "checkin-page",
      "name": "打卡记录",
      "route": "pages/Checkin",
      "tabId": "tab-checkin",
      "semanticTargets": [
        {
          "id": "checkin-calendar",
          "role": "state",
          "binding": "/checkin/calendarDays"
        },
        {
          "id": "checkin-add-button",
          "role": "action",
          "event": "open-add-checkin"
        },
        {
          "id": "checkin-log-list",
          "role": "list",
          "binding": "/checkin/logs",
          "itemIdPattern": "checkin-log-{id}",
          "emptyStateId": "checkin-empty-state"
        },
        {
          "id": "checkin-share-button",
          "role": "action",
          "event": "open-share-checkin"
        },
        {
          "id": "checkin-meal-type-picker",
          "role": "input",
          "binding": "/checkin/newMealType"
        },
        {
          "id": "checkin-dish-name-input",
          "role": "input",
          "binding": "/checkin/newDishName"
        },
        {
          "id": "checkin-note-input",
          "role": "input",
          "binding": "/checkin/newNote"
        },
        {
          "id": "checkin-save-button",
          "role": "action",
          "event": "save-checkin"
        }
      ]
    },
    {
      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile-page",
      "name": "我的",
      "route": "pages/Profile",
      "tabId": "tab-profile",
      "semanticTargets": [
        {
          "id": "profile-clear-data-button",
          "role": "action",
          "event": "clear-all-data"
        },
        {
          "id": "profile-export-button",
          "role": "action",
          "event": "export-checkin-data"
        }
      ]
    },
    {
      "id": "share-card-page",
      "surfaceId": "share-card",
      "pageId": "share-card-page",
      "name": "分享卡片",
      "route": "pages/ShareCard",
      "semanticTargets": [
        {
          "id": "share-card-preview",
          "role": "state",
          "binding": "/share/cardData"
        },
        {
          "id": "share-card-save-button",
          "role": "action",
          "event": "save-share-card"
        },
        {
          "id": "share-card-close-button",
          "role": "action",
          "event": "close-share-card"
        }
      ]
    }
  ],
  "events": [
    { "name": "spin-wheel", "description": "触发转盘随机抽菜" },
    { "name": "open-share-result", "description": "从转盘结果进入分享卡片" },
    { "name": "add-ingredient", "description": "添加冰箱食材" },
    { "name": "remove-ingredient", "description": "删除冰箱食材" },
    { "name": "recommend-by-ingredients", "description": "根据食材推荐菜品" },
    { "name": "filter-dishes", "description": "按心情/时间/口味筛选菜品" },
    { "name": "use-dish", "description": "将筛选结果设为今日决定" },
    { "name": "open-add-checkin", "description": "打开打卡表单" },
    { "name": "save-checkin", "description": "保存打卡记录" },
    { "name": "delete-checkin", "description": "删除打卡记录" },
    { "name": "open-share-checkin", "description": "从打卡进入分享卡片" },
    { "name": "clear-all-data", "description": "清空所有本地数据" },
    { "name": "export-checkin-data", "description": "导出打卡数据" },
    { "name": "save-share-card", "description": "保存分享卡片" },
    { "name": "close-share-card", "description": "关闭分享卡片页" }
  ],
  "bindings": {
    "/wheel/currentIndex": { "type": "number", "description": "转盘当前高亮分区索引" },
    "/wheel/resultDish": { "type": "object", "description": "转盘抽中的菜品对象" },
    "/ingredients/list": { "type": "array", "description": "冰箱食材列表" },
    "/ingredients/newItemText": { "type": "string", "description": "待添加食材输入文本" },
    "/ingredients/recommendResults": { "type": "array", "description": "基于食材的推荐结果" },
    "/mood/selectedMood": { "type": "string", "description": "当前选中的心情标签" },
    "/mood/selectedMealTime": { "type": "string", "description": "当前选中的用餐时段" },
    "/mood/selectedTaste": { "type": "string", "description": "当前选中的口味偏好" },
    "/mood/filterResults": { "type": "array", "description": "筛选后的菜品列表" },
    "/checkin/calendarDays": { "type": "array", "description": "当月日历日期与打卡状态" },
    "/checkin/logs": { "type": "array", "description": "打卡记录列表" },
    "/checkin/newMealType": { "type": "string", "description": "新打卡餐别" },
    "/checkin/newDishName": { "type": "string", "description": "新打卡菜名" },
    "/checkin/newNote": { "type": "string", "description": "新打卡备注" },
    "/share/cardData": { "type": "object", "description": "分享卡片数据" }
  },
  "testTargets": [
    { "id": "home-spin-button", "action": "click", "expect": "转盘开始旋转" },
    { "id": "home-result-card", "assert": "visible", "when": "转盘停止后" },
    { "id": "home-share-result-button", "action": "click", "expect": "进入分享卡片页" },
    { "id": "ingredients-add-button", "action": "click", "expect": "食材列表新增一项" },
    { "id": "ingredients-recommend-button", "action": "click", "expect": "展示推荐菜品列表" },
    { "id": "mood-filter-button", "action": "click", "expect": "展示筛选结果" },
    { "id": "checkin-add-button", "action": "click", "expect": "打卡表单可见" },
    { "id": "checkin-save-button", "action": "click", "expect": "打卡记录列表新增一项" },
    { "id": "share-card-save-button", "action": "click", "expect": "触发保存卡片" },
    { "id": "tab-checkin", "action": "click", "expect": "切换到打卡页" }
  ]
}

